1	package com.civicworks.controller;
2	
3	import com.civicworks.domain.entity.AuditLog;
4	import com.civicworks.service.AuditService;
5	import org.springframework.data.domain.Page;
6	import org.springframework.data.domain.PageRequest;
7	import org.springframework.data.domain.Pageable;
8	import org.springframework.format.annotation.DateTimeFormat;
9	import org.springframework.http.ResponseEntity;
10	import org.springframework.security.access.prepost.PreAuthorize;
11	import org.springframework.web.bind.annotation.*;
12	
13	import java.time.OffsetDateTime;
14	import java.util.Map;
15	
16	@RestController
17	@RequestMapping("/api/v1/audit")
18	public class AuditController {
19	
20	    private final AuditService auditService;
21	
22	    public AuditController(AuditService auditService) {
23	        this.auditService = auditService;
24	    }
25	
26	    /**
27	     * GET /api/v1/audit/logs
28	     *
29	     * Supports filtering by entity_ref, action keyword, and date range.
30	     * Results are always paginated (max 200 per page).
31	     */
32	    @GetMapping("/logs")
33	    @PreAuthorize("hasRole('AUDITOR') or hasRole('SYSTEM_ADMIN')")
34	    public ResponseEntity<Map<String, Object>> getLogs(
35	            @RequestParam(required = false) String entity_ref,
36	            @RequestParam(required = false) String action,
37	            @RequestParam(required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) OffsetDateTime from,
38	            @RequestParam(required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) OffsetDateTime to,
39	            @RequestParam(defaultValue = "0")  int page,
40	            @RequestParam(defaultValue = "50") int size) {
41	
42	        Pageable pageable = PageRequest.of(Math.max(0, page), Math.min(200, size));
43	        Page<AuditLog> result = (entity_ref != null || action != null || from != null || to != null)
44	                ? auditService.findWithFilters(entity_ref, action, from, to, pageable)
45	                : auditService.findAll(pageable);
46	
47	        return ResponseEntity.ok(Map.of(
48	                "data",  result.getContent(),
49	                "page",  result.getNumber(),
50	                "size",  result.getSize(),
51	                "total", result.getTotalElements()
52	        ));
53	    }
54	}
