1	package com.civicworks.service;
2	
3	import com.civicworks.domain.entity.AuditLog;
4	import com.civicworks.repository.AuditLogRepository;
5	import com.fasterxml.jackson.core.JsonProcessingException;
6	import com.fasterxml.jackson.databind.ObjectMapper;
7	import org.slf4j.Logger;
8	import org.slf4j.LoggerFactory;
9	import org.springframework.data.domain.Page;
10	import org.springframework.data.domain.Pageable;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Propagation;
13	import org.springframework.transaction.annotation.Transactional;
14	
15	import java.time.OffsetDateTime;
16	import java.util.Map;
17	import java.util.UUID;
18	
19	@Service
20	public class AuditService {
21	
22	    private static final Logger log = LoggerFactory.getLogger(AuditService.class);
23	
24	    private final AuditLogRepository auditLogRepository;
25	    private final ObjectMapper objectMapper;
26	
27	    public AuditService(AuditLogRepository auditLogRepository, ObjectMapper objectMapper) {
28	        this.auditLogRepository = auditLogRepository;
29	        this.objectMapper = objectMapper;
30	    }
31	
32	    @Transactional(propagation = Propagation.REQUIRES_NEW)
33	    public void log(UUID actorId, String action, String entityRef, Map<String, Object> details) {
34	        AuditLog entry = new AuditLog();
35	        entry.setActorId(actorId);
36	        entry.setAction(action);
37	        entry.setEntityRef(entityRef);
38	        try {
39	            entry.setDetails(objectMapper.writeValueAsString(details));
40	        } catch (JsonProcessingException e) {
41	            entry.setDetails("{}");
42	        }
43	        auditLogRepository.save(entry);
44	        log.info("AUDIT action={} entityRef={} actorId={}", action, entityRef, actorId);
45	    }
46	
47	    @Transactional(propagation = Propagation.REQUIRES_NEW)
48	    public void log(UUID actorId, String action, String entityRef, String rawJson) {
49	        // Backward-compatible overload — stores as-is (caller is responsible for valid JSON)
50	        AuditLog entry = new AuditLog();
51	        entry.setActorId(actorId);
52	        entry.setAction(action);
53	        entry.setEntityRef(entityRef);
54	        entry.setDetails(rawJson);
55	        auditLogRepository.save(entry);
56	        log.info("AUDIT action={} entityRef={} actorId={}", action, entityRef, actorId);
57	    }
58	
59	    @Transactional(readOnly = true)
60	    public Page<AuditLog> findAll(Pageable pageable) {
61	        return auditLogRepository.findAllByOrderByCreatedAtDesc(pageable);
62	    }
63	
64	    @Transactional(readOnly = true)
65	    public Page<AuditLog> findWithFilters(String entityRef, String action,
66	                                           OffsetDateTime from, OffsetDateTime to,
67	                                           Pageable pageable) {
68	        return auditLogRepository.findWithFilters(entityRef, action, from, to, pageable);
69	    }
70	}
