1	package com.civicworks.repository;
2	
3	import com.civicworks.domain.entity.AuditLog;
4	import org.springframework.data.domain.Page;
5	import org.springframework.data.domain.Pageable;
6	import org.springframework.data.jpa.repository.JpaRepository;
7	import org.springframework.data.jpa.repository.Query;
8	import org.springframework.data.repository.query.Param;
9	import org.springframework.stereotype.Repository;
10	
11	import java.time.OffsetDateTime;
12	import java.util.List;
13	import java.util.UUID;
14	
15	@Repository
16	public interface AuditLogRepository extends JpaRepository<AuditLog, UUID> {
17	
18	    List<AuditLog> findByEntityRef(String entityRef);
19	
20	    Page<AuditLog> findAllByOrderByCreatedAtDesc(Pageable pageable);
21	
22	    Page<AuditLog> findAllByOrganizationIdOrderByCreatedAtDesc(UUID organizationId, Pageable pageable);
23	
24	    @Query("""
25	           SELECT a FROM AuditLog a
26	           WHERE (:orgId IS NULL OR a.organizationId = :orgId)
27	             AND (:entityRef IS NULL OR a.entityRef = :entityRef)
28	             AND (:action IS NULL OR a.action = :action)
29	             AND (:from IS NULL OR a.createdAt >= :from)
30	             AND (:to IS NULL OR a.createdAt <= :to)
31	           ORDER BY a.createdAt DESC
32	           """)
33	    Page<AuditLog> findWithFilters(@Param("orgId") UUID orgId,
34	                                   @Param("entityRef") String entityRef,
35	                                   @Param("action") String action,
36	                                   @Param("from") OffsetDateTime from,
37	                                   @Param("to") OffsetDateTime to,
38	                                   Pageable pageable);
39	}
