1	package com.civicworks.service;
2	
3	import com.civicworks.domain.entity.User;
4	import com.civicworks.domain.enums.Role;
5	import com.civicworks.exception.ResourceNotFoundException;
6	import org.springframework.stereotype.Service;
7	
8	import java.util.UUID;
9	
10	/**
11	 * Centralised object-level authorization enforcement.
12	 * <p>
13	 * Every service-layer mutation that accesses an org-scoped entity MUST call
14	 * one of this service's {@code check*} methods <em>before</em> proceeding.
15	 * The checks are intentionally in the service layer (not the controller)
16	 * so they cannot be bypassed by alternative entry points such as schedulers
17	 * or message listeners.
18	 *
19	 * <h3>Bypass rules</h3>
20	 * <ul>
21	 *   <li>{@code actor == null} — scheduler / system call → global access</li>
22	 *   <li>{@code actor.role == SYSTEM_ADMIN} → global access</li>
23	 *   <li>{@code actor.organization == null} — unscoped user → global access (no org to restrict to)</li>
24	 * </ul>
25	 *
26	 * All other actors are restricted to entities whose {@code organizationId}
27	 * matches their own.  A mismatch throws {@link ResourceNotFoundException}
28	 * (returns HTTP 404 to the caller, preventing enumeration).
29	 */
30	@Service
31	public class AuthorizationService {
32	
33	    /**
34	     * Resolves the effective org-id for tenant isolation.
35	     * Returns {@code null} when the caller has global access.
36	     */
37	    public static UUID resolveOrgId(User actor) {
38	        if (actor == null) return null;
39	        if (actor.getRole() == Role.SYSTEM_ADMIN) return null;
40	        return actor.getOrganization() != null ? actor.getOrganization().getId() : null;
41	    }
42	
43	    /**
44	     * Asserts that the caller's organisation matches the entity's organisation.
45	     *
46	     * @param entityOrgId the organisation id stored on the entity
47	     * @param actor       the authenticated user
48	     * @param entityType  label used in the 404 message (e.g. "Bill", "ContentItem")
49	     * @param entityId    the entity's primary key (used in the 404 message)
50	     * @throws ResourceNotFoundException if the org ids do not match
51	     */
52	    public static void checkOwnership(UUID entityOrgId, User actor,
53	                                       String entityType, UUID entityId) {
54	        UUID actorOrgId = resolveOrgId(actor);
55	        if (actorOrgId == null) return;                       // global access
56	        if (actorOrgId.equals(entityOrgId)) return;           // same org
57	        throw new ResourceNotFoundException(entityType, entityId);
58	    }
59	}
