1	package com.civicworks.unit;
2	
3	import com.civicworks.domain.entity.ContentItem;
4	import com.civicworks.domain.entity.Organization;
5	import com.civicworks.domain.entity.User;
6	import com.civicworks.domain.enums.ContentState;
7	import com.civicworks.domain.enums.Role;
8	import com.civicworks.exception.ResourceNotFoundException;
9	import com.civicworks.repository.ContentItemRepository;
10	import com.civicworks.repository.ContentPublishSnapshotRepository;
11	import com.civicworks.scheduler.QuartzSchedulerConfig;
12	import com.civicworks.service.AuditService;
13	import com.civicworks.service.ContentService;
14	import com.civicworks.service.HtmlSanitizerService;
15	import com.civicworks.service.NotificationService;
16	import org.junit.jupiter.api.BeforeEach;
17	import org.junit.jupiter.api.Test;
18	import org.junit.jupiter.api.extension.ExtendWith;
19	import org.mockito.Mock;
20	import org.mockito.junit.jupiter.MockitoExtension;
21	import org.mockito.junit.jupiter.MockitoSettings;
22	import org.mockito.quality.Strictness;
23	import org.springframework.data.domain.PageImpl;
24	import org.springframework.data.domain.Pageable;
25	
26	import java.util.List;
27	import java.util.Optional;
28	import java.util.UUID;
29	
30	import static org.assertj.core.api.Assertions.*;
31	import static org.mockito.ArgumentMatchers.*;
32	import static org.mockito.Mockito.*;
33	
34	/**
35	 * Verifies content tenant isolation:
36	 * - User from org A cannot read, update, publish, or comment on org B content
37	 * - SYSTEM_ADMIN can access any content
38	 * - findAll returns only org-scoped results for non-admin users
39	 */
40	@ExtendWith(MockitoExtension.class)
41	@MockitoSettings(strictness = Strictness.LENIENT)
42	class CrossTenantContentTest {
43	
44	    @Mock ContentItemRepository contentItemRepository;
45	    @Mock ContentPublishSnapshotRepository snapshotRepository;
46	    @Mock AuditService auditService;
47	    @Mock QuartzSchedulerConfig quartzSchedulerConfig;
48	    @Mock NotificationService notificationService;
49	
50	    private ContentService contentService;
51	
52	    private final UUID itemId = UUID.randomUUID();
53	    private final UUID orgA = UUID.randomUUID();
54	    private final UUID orgB = UUID.randomUUID();
55	
56	    @BeforeEach
57	    void setUp() {
58	        contentService = new ContentService(
59	                contentItemRepository, snapshotRepository,
60	                auditService, quartzSchedulerConfig, new HtmlSanitizerService(),
61	                notificationService);
62	    }
63	
64	    // ── findById ──────────────────────────────────────────────────────────
65	
66	    @Test
67	    void editorFromOrgA_cannotRead_itemInOrgB() {
68	        when(contentItemRepository.findByIdAndOrganizationId(itemId, orgA))
69	                .thenReturn(Optional.empty());
70	
71	        User editorA = editorInOrg(orgA);
72	
73	        assertThatThrownBy(() -> contentService.findById(itemId, editorA))
74	                .isInstanceOf(ResourceNotFoundException.class);
75	    }
76	
77	    @Test
78	    void editorFromOrgB_canRead_itemInOrgB() {
79	        ContentItem item = itemInOrg(orgB);
80	        when(contentItemRepository.findByIdAndOrganizationId(itemId, orgB))
81	                .thenReturn(Optional.of(item));
82	
83	        User editorB = editorInOrg(orgB);
84	
85	        assertThatCode(() -> contentService.findById(itemId, editorB))
86	                .doesNotThrowAnyException();
87	    }
88	
89	    @Test
90	    void systemAdmin_canRead_anyItem() {
91	        ContentItem item = itemInOrg(orgB);
92	        when(contentItemRepository.findById(itemId)).thenReturn(Optional.of(item));
93	
94	        User admin = adminInOrg(orgA);
95	
96	        assertThatCode(() -> contentService.findById(itemId, admin))
97	                .doesNotThrowAnyException();
98	    }
99	
100	    // ── publishItem ───────────────────────────────────────────────────────
101	
102	    @Test
103	    void editorFromOrgA_cannotPublish_itemInOrgB() {
104	        ContentItem item = itemInOrg(orgB);
105	        item.setState(ContentState.DRAFT);
106	        when(contentItemRepository.findById(itemId)).thenReturn(Optional.of(item));
107	
108	        User editorA = editorInOrg(orgA);
109	
110	        assertThatThrownBy(() -> contentService.publishItem(itemId, 0, editorA))
111	                .isInstanceOf(ResourceNotFoundException.class);
112	    }
113	
114	    // ── findAll ───────────────────────────────────────────────────────────
115	
116	    @Test
117	    void findAll_nonAdmin_usesOrgScopedQuery() {
118	        when(contentItemRepository.findWithFiltersAndOrg(eq(orgA), isNull(), isNull(), any(Pageable.class)))
119	                .thenReturn(new PageImpl<>(List.of()));
120	
121	        User editorA = editorInOrg(orgA);
122	        contentService.findAll(null, null, null,
123	                org.springframework.data.domain.PageRequest.of(0, 20), editorA);
124	
125	        // Must use the org-scoped query, NOT the unscoped one
126	        verify(contentItemRepository).findWithFiltersAndOrg(eq(orgA), isNull(), isNull(), any(Pageable.class));
127	        verify(contentItemRepository, never()).findWithFilters(any(), any(), any(Pageable.class));
128	    }
129	
130	    @Test
131	    void findAll_admin_usesGlobalQuery() {
132	        when(contentItemRepository.findWithFilters(isNull(), isNull(), any(Pageable.class)))
133	                .thenReturn(new PageImpl<>(List.of()));
134	
135	        User admin = adminInOrg(orgA);
136	        contentService.findAll(null, null, null,
137	                org.springframework.data.domain.PageRequest.of(0, 20), admin);
138	
139	        verify(contentItemRepository).findWithFilters(isNull(), isNull(), any(Pageable.class));
140	        verify(contentItemRepository, never()).findWithFiltersAndOrg(any(), any(), any(), any(Pageable.class));
141	    }
142	
143	    // ── search ────────────────────────────────────────────────────────────
144	
145	    @Test
146	    void search_nonAdmin_usesOrgScopedFullText() {
147	        when(contentItemRepository.fullTextSearchByOrg(eq(orgA), eq("test"), isNull(), isNull()))
148	                .thenReturn(List.of());
149	
150	        User editorA = editorInOrg(orgA);
151	        contentService.search("test", null, null, editorA);
152	
153	        verify(contentItemRepository).fullTextSearchByOrg(eq(orgA), eq("test"), isNull(), isNull());
154	        verify(contentItemRepository, never()).fullTextSearch(any(), any(), any());
155	    }
156	
157	    // ── helpers ────────────────────────────────────────────────────────────
158	
159	    private ContentItem itemInOrg(UUID orgId) {
160	        ContentItem item = new ContentItem();
161	        item.setId(itemId);
162	        item.setTitle("Test Item");
163	        item.setState(ContentState.DRAFT);
164	        Organization org = new Organization();
165	        org.setId(orgId);
166	        item.setOrganization(org);
167	        return item;
168	    }
169	
170	    private User editorInOrg(UUID orgId) {
171	        User u = new User();
172	        u.setId(UUID.randomUUID());
173	        u.setRole(Role.CONTENT_EDITOR);
174	        Organization org = new Organization();
175	        org.setId(orgId);
176	        u.setOrganization(org);
177	        return u;
178	    }
179	
180	    private User adminInOrg(UUID orgId) {
181	        User u = new User();
182	        u.setId(UUID.randomUUID());
183	        u.setRole(Role.SYSTEM_ADMIN);
184	        Organization org = new Organization();
185	        org.setId(orgId);
186	        u.setOrganization(org);
187	        return u;
188	    }
189	}
