1	package com.civicworks.domain.entity;
2	
3	import jakarta.persistence.*;
4	import org.hibernate.annotations.CreationTimestamp;
5	
6	import java.time.OffsetDateTime;
7	import java.util.UUID;
8	
9	@Entity
10	@Table(name = "organizations")
11	public class Organization {
12	
13	    @Id
14	    @GeneratedValue(strategy = GenerationType.UUID)
15	    @Column(name = "id", updatable = false, nullable = false)
16	    private UUID id;
17	
18	    @Column(name = "name", nullable = false)
19	    private String name;
20	
21	    @CreationTimestamp
22	    @Column(name = "created_at", nullable = false, updatable = false)
23	    private OffsetDateTime createdAt;
24	
25	    public Organization() {}
26	
27	    public UUID getId() { return id; }
28	    public void setId(UUID id) { this.id = id; }
29	
30	    public String getName() { return name; }
