        entry.setEntityRef(entityRef);
        entry.setDetails(rawJson);
        auditLogRepository.save(entry);
        log.info("AUDIT action={} entityRef={} actorId={}", action, entityRef, actorId);
    }

    @Transactional(readOnly = true)
