1	package com.civicworks.service;
2	
3	import com.civicworks.domain.entity.KpiReport;
4	import com.civicworks.repository.KpiReportRepository;
5	import org.slf4j.Logger;
6	import org.slf4j.LoggerFactory;
7	import org.springframework.stereotype.Service;
8	import org.springframework.transaction.annotation.Transactional;
9	
10	import java.math.BigDecimal;
11	import java.math.RoundingMode;
12	import java.time.DayOfWeek;
13	import java.time.LocalDate;
14	import java.time.OffsetDateTime;
15	import java.util.UUID;
16	
17	@Service
18	public class KpiService {
19	
20	    private static final Logger log = LoggerFactory.getLogger(KpiService.class);
21	
22	    private static final double ANOMALY_THRESHOLD_PCT = 15.0;
23	
24	    private final KpiReportRepository kpiReportRepository;
25	
26	    public KpiService(KpiReportRepository kpiReportRepository) {
27	        this.kpiReportRepository = kpiReportRepository;
28	    }
29	
30	    /**
31	     * Generates (or replaces) the weekly KPI report for the given organisation.
32	     *
33	     * <p>Week boundaries are aligned to ISO Monday.  The report is for the week
34	     * that started on the most recent Monday on or before today; the prior-week
35	     * row (week_start = previous Monday) is used for the WoW comparison.
36	     *
37	     * <p>An anomaly is flagged when {@code wow_change_pct > 15.0} and the prior
38	     * week had a non-zero arrears balance (division-by-zero guard).
39	     */
40	    @Transactional
41	    public KpiReport generateWeeklyReport(UUID orgId) {
42	        LocalDate thisMonday  = mostRecentMonday(LocalDate.now());
43	        LocalDate priorMonday = thisMonday.minusWeeks(1);
44	
45	        // --- current arrears (OPEN + OVERDUE bills) ---
46	        long currentArrears = kpiReportRepository.sumArrearsByOrganization(orgId);
47	
48	        // --- prior week ---
49	        Long priorArrears = kpiReportRepository
50	                .findByOrganizationIdAndWeekStart(orgId, priorMonday)
51	                .map(KpiReport::getTotalArrearsCents)
52	                .orElse(null);
53	
54	        // --- WoW % change and anomaly flag ---
55	        BigDecimal wowPct    = null;
56	        boolean    anomaly   = false;
57	
58	        if (priorArrears != null && priorArrears > 0) {
59	            double pct = ((double) (currentArrears - priorArrears) / priorArrears) * 100.0;
60	            wowPct  = BigDecimal.valueOf(pct).setScale(4, RoundingMode.HALF_UP);
61	            anomaly = pct > ANOMALY_THRESHOLD_PCT;
62	        }
63	
64	        // --- upsert ---
65	        KpiReport report = kpiReportRepository
66	                .findByOrganizationIdAndWeekStart(orgId, thisMonday)
67	                .orElseGet(KpiReport::new);
68	
69	        report.setOrganizationId(orgId);
70	        report.setWeekStart(thisMonday);
71	        report.setTotalArrearsCents(currentArrears);
72	        report.setPriorWeekArrearsCents(priorArrears);
73	        report.setWowChangePct(wowPct);
74	        report.setAnomalyFlag(anomaly);
75	        report.setGeneratedAt(OffsetDateTime.now());
76	
77	        KpiReport saved = kpiReportRepository.save(report);
78	
79	        if (anomaly) {
80	            log.warn("KPI_ANOMALY_DETECTED orgId={} pct={}", orgId,
81	                    wowPct != null ? wowPct.toPlainString() : "N/A");
82	        }
83	
84	        return saved;
85	    }
86	
87	    // -------------------------------------------------------------------------
88	
89	    /** Returns the most recent Monday on or before the given date (ISO week). */
90	    public static LocalDate mostRecentMonday(LocalDate date) {
91	        return date.with(DayOfWeek.MONDAY).isAfter(date)
92	                ? date.with(DayOfWeek.MONDAY).minusWeeks(1)
93	                : date.with(DayOfWeek.MONDAY);
94	    }
95	}
