66	    @Transactional
67	    public DispatchOrder createOrder(CreateDispatchOrderRequest request, User actor) {
68	        Zone zone = zoneRepository.findById(request.getZoneId())
69	                .orElseThrow(() -> new ResourceNotFoundException("Zone", request.getZoneId()));
70	
71	        long activeOrders = dispatchOrderRepository.countActiveOrdersInZone(request.getZoneId(),
72	                List.of(OrderStatus.ASSIGNED, OrderStatus.ACCEPTED));
73	
74	        DispatchOrder order = new DispatchOrder();
75	        order.setZoneId(request.getZoneId());
76	        order.setMode(request.getMode());
77	        order.setPickupLat(request.getPickupLat());
78	        order.setPickupLng(request.getPickupLng());
79	        order.setDropoffLat(request.getDropoffLat());
80	        order.setDropoffLng(request.getDropoffLng());
81	        order.setForcedFlag(request.isForcedFlag());
82	        if (actor.getOrganization() != null) {
83	            order.setOrganizationId(actor.getOrganization().getId());
84	        }
85	
86	        if (activeOrders >= zone.getMaxConcurrentOrders()) {
87	            order.setStatus(OrderStatus.QUEUED);
88	            DispatchOrder saved = dispatchOrderRepository.save(order);
89	
90	            int nextPos = zoneQueueRepository.maxQueuePositionForZone(request.getZoneId()) + 1;
91	            ZoneQueue q = new ZoneQueue();
92	            q.setZoneId(request.getZoneId());
93	            q.setOrderId(saved.getId());
94	            q.setQueuePosition(nextPos);
95	            q.setStatus("WAITING");
96	            zoneQueueRepository.save(q);
97	
98	            return saved;
99	        }
100	
101	        // Handle forced dispatch assignment
102	        if (request.isForcedFlag() && request.getAssignedDriverId() != null) {
103	            order.setAssignedDriverId(request.getAssignedDriverId());
104	            order.setAssignedAt(OffsetDateTime.now());
105	            order.setStatus(OrderStatus.ASSIGNED);
106	            auditService.log(actor.getId(), "DISPATCH_ORDER_FORCED_ASSIGNED",
107	                    "dispatch_orders/", Map.of("driverId", request.getAssignedDriverId().toString()));
108	        } else {
109	            order.setStatus(OrderStatus.PENDING);
110	        }
111	
112	        DispatchOrder saved = dispatchOrderRepository.save(order);
113	
114	        // Notify assigned driver of new dispatch assignment
115	        if (saved.getAssignedDriverId() != null) {
116	            notifyDriver(saved.getAssignedDriverId(), "DISPATCH_ASSIGNED",
117	                    "New dispatch assignment",
118	                    "You have been assigned dispatch order " + saved.getId() + ".",
119	                    "dispatch_orders/" + saved.getId());
120	        }
121	
122	        return saved;
123	    }
