141	    @Transactional
142	    public DispatchOrder acceptOrder(UUID orderId, Integer entityVersion, User driver) {
143	        DispatchOrder order = loadOrderWithTenantCheck(orderId, driver);
144	
145	        requireVersion(entityVersion, order.getVersion(), "DispatchOrder", orderId,
146	                Map.of("status", order.getStatus().name()));
147	
148	        if (order.getStatus() != OrderStatus.PENDING && order.getStatus() != OrderStatus.ASSIGNED) {
149	            throw new BusinessException("Order is not in an acceptable state: " + order.getStatus(), HttpStatus.UNPROCESSABLE_ENTITY);
150	        }
151	
152	        requireForcedDispatchDriverMatch(order, driver);
153	
154	        // Check eligibility
155	        checkDriverEligibility(driver.getId());
156	
157	        order.setAssignedDriverId(driver.getId());
158	        order.setAssignedAt(OffsetDateTime.now());
159	        order.setStatus(OrderStatus.ACCEPTED);
160	        DispatchOrder saved = dispatchOrderRepository.save(order);
161	
162	        MDC.put("orderId", orderId.toString());
163	        log.info("ORDER_ACCEPTED driverId={}", driver.getId());
164	        MDC.remove("orderId");
165	
166	        auditService.log(driver.getId(), "DISPATCH_ORDER_ACCEPTED",
167	                "dispatch_orders/" + orderId, Map.of("driverId", driver.getId().toString()));
168	
169	        notifyDriver(driver.getId(), "DISPATCH_ACCEPTED",
170	                "Dispatch order accepted",
171	                "You have accepted dispatch order " + orderId + ".",
