177	    /**
178	     * Accept an order.  Driver coordinates are <strong>mandatory</strong>: if
179	     * {@code request} is null or either coordinate is absent the acceptance is
180	     * rejected immediately with a 400 Bad Request.  The distance check cannot
181	     * be bypassed by omitting coordinates.
182	     *
183	     * <p>Distance check is performed only when the order also has pickup
184	     * coordinates stored.  If the order has no pickup coordinates the distance
185	     * constraint is evaluated without a location source and passes through,
186	     * but the driver still undergoes all other eligibility checks (rating,
187	     * online time, cooldown).
188	     */
189	    @Transactional
190	    public DispatchOrder acceptOrder(UUID orderId, Integer entityVersion, User driver,
191	                                     AcceptOrderRequest request) {
192	        // Driver coordinates are mandatory — no bypass allowed.
193	        if (request == null || request.getDriverLat() == null || request.getDriverLng() == null) {
194	            throw new BusinessException(
195	                    "Driver coordinates (driverLat, driverLng) are required to accept an order",
196	                    HttpStatus.BAD_REQUEST);
197	        }
198	
199	        DispatchOrder order = loadOrderWithTenantCheck(orderId, driver);
200	
201	        // Pickup coordinates are required on the order — distance cannot be verified without them.
202	        if (order.getPickupLat() == null || order.getPickupLng() == null) {
203	            throw new BusinessException(
204	                    "Order pickup coordinates are missing; acceptance is not permitted without a verifiable pickup location",
205	                    HttpStatus.BAD_REQUEST);
206	        }
207	
208	        requireVersion(entityVersion, order.getVersion(), "DispatchOrder", orderId,
209	                Map.of("status", order.getStatus().name()));
210	
211	        if (order.getStatus() != OrderStatus.PENDING && order.getStatus() != OrderStatus.ASSIGNED) {
212	            throw new BusinessException("Order is not in an acceptable state: " + order.getStatus(),
213	                    HttpStatus.UNPROCESSABLE_ENTITY);
214	        }
215	
216	        requireForcedDispatchDriverMatch(order, driver);
217	
218	        Double driverLat = request.getDriverLat();
219	        Double driverLng = request.getDriverLng();
220	        Double orderLat  = order.getPickupLat().doubleValue();
221	        Double orderLng  = order.getPickupLng().doubleValue();
222	
223	        Map<String, Object> eligibility = checkDriverEligibility(driver.getId(),
224	                driverLat, driverLng, orderLat, orderLng);
225	        if (!(boolean) eligibility.get("eligible")) {
226	            throw new BusinessException(
227	                    "Driver is not eligible to accept this order: " + eligibility.get("reasons"),
228	                    HttpStatus.UNPROCESSABLE_ENTITY);
229	        }
230	
231	        order.setAssignedDriverId(driver.getId());
232	        order.setAssignedAt(OffsetDateTime.now());
233	        order.setStatus(OrderStatus.ACCEPTED);
234	        DispatchOrder saved = dispatchOrderRepository.save(order);
235	
236	        MDC.put("orderId", orderId.toString());
237	        log.info("ORDER_ACCEPTED driverId={}", driver.getId());
238	        MDC.remove("orderId");
239	
240	        auditService.log(driver.getId(), "DISPATCH_ORDER_ACCEPTED",
241	                "dispatch_orders/" + orderId, Map.of("driverId", driver.getId().toString()));
242	
243	        notifyDriver(driver.getId(), "DISPATCH_ACCEPTED",
244	                "Dispatch order accepted",
245	                "You have accepted dispatch order " + orderId + ".",
246	                "dispatch_orders/" + orderId);
247	
248	        return saved;
249	    }
