251	    @Transactional
252	    public DispatchOrder rejectOrder(UUID orderId, RejectOrderRequest request, User driver) {
253	        DispatchOrder order = loadOrderWithTenantCheck(orderId, driver);
254	
255	        requireVersion(request.getEntityVersion(), order.getVersion(), "DispatchOrder", orderId,
256	                Map.of("status", order.getStatus().name()));
257	
258	        if (order.getStatus() != OrderStatus.PENDING && order.getStatus() != OrderStatus.ASSIGNED
259	                && order.getStatus() != OrderStatus.ACCEPTED) {
260	            throw new BusinessException("Order cannot be rejected in state: " + order.getStatus(),
261	                    HttpStatus.UNPROCESSABLE_ENTITY);
262	        }
263	
264	        boolean wasForced = order.isForcedFlag();
265	        RejectionReason reason = request.getRejectionReason();
266	
267	        // Store standardised rejection reason and reset order for reassignment.
268	        // The order goes back to PENDING (not a terminal REJECTED state) so that
269	        // another eligible driver can accept it.  The rejecting driver enters a
270	        // 30-minute cooldown that the eligibility check will enforce.
271	        order.setRejectionReason(reason.name());
272	        order.setAssignedDriverId(null);
273	        order.setAssignedAt(null);
274	        order.setStatus(OrderStatus.PENDING);
275	        DispatchOrder saved = dispatchOrderRepository.save(order);
276	
277	        // 30-minute exclusion for the rejecting driver
278	        DriverCooldown cooldown = new DriverCooldown();
279	        cooldown.setDriverId(driver.getId());
280	        cooldown.setOrderId(orderId);
281	        cooldown.setCooldownUntil(OffsetDateTime.now().plusMinutes(COOLDOWN_MINUTES));
282	        driverCooldownRepository.save(cooldown);
283	
284	        MDC.put("orderId", orderId.toString());
285	        log.info("ORDER_REJECTED driverId={} reason={} wasForced={}", driver.getId(), reason, wasForced);
286	        MDC.remove("orderId");
287	
288	        auditService.log(driver.getId(), "DISPATCH_ORDER_REJECTED",
289	                "dispatch_orders/" + orderId,
290	                Map.of("reason", reason.name(), "forced", wasForced));
291	
292	        return saved;
293	    }
294	
295	    /**
296	     * Promotes the next WAITING entry in the zone queue to an active PENDING
297	     * order.  Call this whenever an order slot in the zone is freed (e.g. order
298	     * completed or cancelled externally).
299	     */
300	    @Transactional
301	    public void promoteNextQueuedOrder(UUID zoneId) {
302	        List<ZoneQueue> waiting =
303	                zoneQueueRepository.findByZoneIdAndStatusOrderByQueuePosition(zoneId, "WAITING");
304	        if (waiting.isEmpty()) return;
305	
306	        ZoneQueue next = waiting.get(0);
307	        dispatchOrderRepository.findById(next.getOrderId()).ifPresent(queued -> {
308	            if (queued.getStatus() == OrderStatus.QUEUED) {
309	                queued.setStatus(OrderStatus.PENDING);
310	                dispatchOrderRepository.save(queued);
311	                log.info("QUEUE_ORDER_PROMOTED orderId={} zoneId={}", queued.getId(), zoneId);
312	            }
313	        });
314	        next.setStatus("PROMOTED");
315	        zoneQueueRepository.save(next);
316	    }
