318	    @Transactional(readOnly = true)
319	    public Map<String, Object> checkDriverEligibility(UUID driverId) {
320	        User driver = userRepository.findById(driverId)
321	                .orElseThrow(() -> new ResourceNotFoundException("Driver", driverId));
322	
323	        boolean eligible = true;
324	        StringBuilder reasons = new StringBuilder();
325	
326	        // Check rating
327	        double rating = driver.getRating() != null ? driver.getRating() : 0.0;
328	        if (rating < MIN_DRIVER_RATING) {
329	            eligible = false;
330	            reasons.append("Rating ").append(rating).append(" < ").append(MIN_DRIVER_RATING).append(". ");
331	        }
332	
333	        // Check online time today
334	        Double minutesToday = driverOnlineSessionRepository.sumMinutesForDriverOnDate(driverId, LocalDate.now());
335	        double mins = minutesToday != null ? minutesToday : 0.0;
336	        if (mins < MIN_ONLINE_MINUTES) {
337	            eligible = false;
338	            reasons.append("Online today: ").append(mins).append(" min < ").append(MIN_ONLINE_MINUTES).append(" min. ");
339	        }
340	
341	        // Check cooldown
342	        boolean inCooldown = driverCooldownRepository.existsByDriverIdAndCooldownUntilAfter(driverId, OffsetDateTime.now());
343	        if (inCooldown) {
344	            eligible = false;
345	            reasons.append("Driver is in cooldown period. ");
346	        }
347	
348	        return Map.of(
349	                "driverId", driverId,
350	                "eligible", eligible,
351	                "rating", rating,
352	                "onlineMinutesToday", mins,
353	                "inCooldown", inCooldown,
354	                "reasons", reasons.toString().trim()
355	        );
356	    }
