358	    /**
359	     * Eligibility check that also enforces the maximum driver-to-pickup distance.
360	     * When all four coordinate parameters are non-null the Haversine distance is
361	     * computed; if it exceeds {@value #MAX_DRIVER_MILES} miles the driver is
362	     * marked ineligible and the reason string is updated accordingly.
363	     */
364	    @Transactional(readOnly = true)
365	    public Map<String, Object> checkDriverEligibility(UUID driverId,
366	                                                       Double driverLat, Double driverLng,
367	                                                       Double orderLat, Double orderLng) {
368	        // Delegate to the existing 1-arg check for the base criteria
369	        Map<String, Object> base = checkDriverEligibility(driverId);
370	
371	        // If all four coordinates are present, apply the distance constraint
372	        if (driverLat == null || driverLng == null || orderLat == null || orderLng == null) {
373	            return base;
374	        }
375	
376	        double distanceMiles = GeoUtils.haversineDistanceMiles(driverLat, driverLng, orderLat, orderLng);
377	        if (distanceMiles <= MAX_DRIVER_MILES) {
378	            return base;
379	        }
380	
381	        // Driver is too far — build an updated result map
382	        boolean wasEligible = (boolean) base.get("eligible");
383	        String existingReasons = (String) base.get("reasons");
384	        String distanceReason = String.format(
385	                "Driver is %.2f miles from pickup, max %.1f miles.", distanceMiles, MAX_DRIVER_MILES);
386	        String combinedReasons = existingReasons.isEmpty()
387	                ? distanceReason
388	                : existingReasons + " " + distanceReason;
389	
390	        Map<String, Object> updated = new LinkedHashMap<>(base);
391	        updated.put("eligible", false);
392	        updated.put("reasons", combinedReasons);
393	        return updated;
394	    }
