401	    /**
402	     * Reassigns a forced-dispatch order to a different driver.
403	     * <p>Requires that the order is currently ASSIGNED (not yet accepted) and
404	     * that at least 30 minutes have elapsed since the original assignment.
405	     */
406	    @Transactional
407	    public DispatchOrder reassignOrder(UUID orderId, Integer entityVersion, UUID newDriverId, User actor) {
408	        DispatchOrder order = loadOrderWithTenantCheck(orderId, actor);
409	
410	        requireVersion(entityVersion, order.getVersion(), "DispatchOrder", orderId,
411	                Map.of("status", order.getStatus().name()));
412	
413	        if (order.getStatus() != OrderStatus.ASSIGNED) {
414	            throw new BusinessException(
415	                    "Only ASSIGNED orders can be reassigned; current status: " + order.getStatus(),
416	                    HttpStatus.UNPROCESSABLE_ENTITY);
417	        }
418	
419	        if (order.getAssignedAt() != null
420	                && order.getAssignedAt().plusMinutes(COOLDOWN_MINUTES).isAfter(OffsetDateTime.now())) {
421	            throw new BusinessException(
422	                    "Cannot reassign before 30 minutes have elapsed since original assignment",
423	                    HttpStatus.UNPROCESSABLE_ENTITY);
424	        }
425	
426	        order.setAssignedDriverId(newDriverId);
427	        order.setAssignedAt(OffsetDateTime.now());
428	        DispatchOrder saved = dispatchOrderRepository.save(order);
429	
430	        log.info("ORDER_REASSIGNED orderId={} newDriverId={}", orderId, newDriverId);
431	
432	        auditService.log(actor.getId(), "DISPATCH_ORDER_REASSIGNED",
433	                "dispatch_orders/" + orderId,
434	                Map.of("newDriverId", newDriverId.toString()));
435	
436	        return saved;
437	    }
438	
439	    // -------------------------------------------------------------------------
440	    // Helpers
441	    // -------------------------------------------------------------------------
442	
443	    private DispatchOrder loadOrderWithTenantCheck(UUID orderId, User actor) {
444	        UUID orgId = AuthorizationService.resolveOrgId(actor);
445	        if (orgId != null) {
446	            return dispatchOrderRepository.findByIdAndOrganizationId(orderId, orgId)
447	                    .orElseThrow(() -> new ResourceNotFoundException("DispatchOrder", orderId));
448	        }
449	        return dispatchOrderRepository.findById(orderId)
450	                .orElseThrow(() -> new ResourceNotFoundException("DispatchOrder", orderId));
451	    }
452	
453	    private void notifyDriver(UUID driverId, String type, String title, String body, String entityRef) {
454	        try {
455	            notificationService.createNotification(driverId, type, title, body, entityRef);
456	        } catch (Exception e) {
457	            log.warn("Failed to send dispatch event notification: {}", e.getMessage());
458	        }
459	    }
460	
461	    /**
462	     * Guards forced-dispatch acceptance integrity.
463	     * <p>
464	     * Any order that was force-assigned (forcedFlag == true), has mode
465	     * DISPATCHER_ASSIGNED, <em>or</em> is currently in ASSIGNED status with
466	     * a pre-set assignedDriverId <strong>must</strong> only be accepted by
467	     * the designated driver.  This prevents hijacking by another driver.
468	     */
469	    private static void requireForcedDispatchDriverMatch(DispatchOrder order, User driver) {
470	        boolean isForced = order.isForcedFlag()
471	                || order.getMode() == OrderMode.DISPATCHER_ASSIGNED
472	                || order.getStatus() == OrderStatus.ASSIGNED;
473	        if (isForced
474	                && order.getAssignedDriverId() != null
475	                && !order.getAssignedDriverId().equals(driver.getId())) {
476	            throw new BusinessException(
477	                    "Only the designated driver may accept a forced-dispatch order",
478	                    HttpStatus.FORBIDDEN);
479	        }
480	    }
481	
482	    private static void requireVersion(Integer requestedVersion, Integer serverVersion,
483	                                        String entityType, UUID entityId,
484	                                        Map<String, Object> stateSummary) {
485	        if (requestedVersion == null || !requestedVersion.equals(serverVersion)) {
486	            throw new VersionConflictException(entityType, entityId, serverVersion, stateSummary);
487	        }
488	    }
489	}
