1	package com.civicworks.config;
2	
3	import com.civicworks.domain.entity.IdempotencyRecord;
4	import com.civicworks.exception.BusinessException;
5	import com.civicworks.service.IdempotencyService;
6	import org.springframework.http.HttpStatus;
7	import com.fasterxml.jackson.core.JsonProcessingException;
8	import com.fasterxml.jackson.databind.ObjectMapper;
9	import org.slf4j.Logger;
10	import org.slf4j.LoggerFactory;
11	import org.springframework.http.HttpStatus;
12	import org.springframework.http.ResponseEntity;
13	import org.springframework.stereotype.Component;
14	
15	import java.util.Optional;
16	import java.util.UUID;
17	import java.util.function.Supplier;
18	
19	/**
20	 * Thin helper that wraps idempotency check-then-execute logic so controllers
21	 * do not duplicate the pattern.
22	 *
23	 * Usage in a controller:
24	 * <pre>
25	 *   return idempotencyGuard.execute(
26	 *       idempotencyKey, actor.getId(), "PUBLISH_CONTENT",
27	 *       () -> ResponseEntity.ok(contentService.publishItem(id, actor)));
28	 * </pre>
29	 *
30	 * If idempotencyKey is null or blank the supplier is executed directly (no
31	 * idempotency tracking — callers should log a warning if the header is absent
32	 * for important mutations).
33	 */
34	@Component
35	public class IdempotencyGuard {
36	
37	    private static final Logger log = LoggerFactory.getLogger(IdempotencyGuard.class);
38	
39	    private final IdempotencyService idempotencyService;
40	    private final ObjectMapper objectMapper;
41	
42	    public IdempotencyGuard(IdempotencyService idempotencyService, ObjectMapper objectMapper) {
43	        this.idempotencyService = idempotencyService;
44	        this.objectMapper = objectMapper;
45	    }
46	
47	    /**
48	     * Executes {@code action} exactly once per (userId, idempotencyKey) pair.
49	     * If the key has been seen before the original response is returned
50	     * immediately without re-executing the action.
51	     *
52	     * @param idempotencyKey  value of the Idempotency-Key header (may be null)
53	     * @param userId          authenticated user's id
54	     * @param actionType      label stored for auditing (e.g. "PUBLISH_CONTENT")
55	     * @param action          the actual work to perform
56	     * @param <T>             response body type
57	     */
58	    @SuppressWarnings("unchecked")
59	    public <T> ResponseEntity<T> execute(String idempotencyKey, UUID userId,
60	                                         String actionType, Supplier<ResponseEntity<T>> action) {
61	        if (idempotencyKey == null || idempotencyKey.isBlank()) {
62	            throw new BusinessException(
63	                    "Idempotency-Key header is required for this operation.",
64	                    HttpStatus.BAD_REQUEST, "IDEMPOTENCY_KEY_REQUIRED");
65	        }
66	
67	        // Check for an existing record with this key for this user.
68	        Optional<IdempotencyRecord> existing = idempotencyService.findExisting(userId, idempotencyKey);
69	        if (existing.isPresent()) {
70	            IdempotencyRecord record = existing.get();
71	            log.info("IDEMPOTENCY_REPLAY key={} actionType={} userId={}", idempotencyKey, actionType, userId);
72	            HttpStatus status = HttpStatus.valueOf(record.getResponseStatus() != null
73	                    ? record.getResponseStatus() : 200);
74	            try {
75	                T body = record.getResponseBody() != null
76	                        ? (T) objectMapper.readValue(record.getResponseBody(), Object.class)
77	                        : null;
78	                return ResponseEntity.status(status).body(body);
79	            } catch (JsonProcessingException e) {
80	                // Cached body unparseable — re-execute rather than returning garbage.
81	                log.warn("IDEMPOTENCY_REPLAY_PARSE_FAIL key={}, re-executing", idempotencyKey);
82	            }
83	        }
84	
85	        // Execute and persist result.
86	        ResponseEntity<T> response = action.get();
87	
88	        try {
89	            String body = objectMapper.writeValueAsString(response.getBody());
90	            idempotencyService.save(userId, idempotencyKey, actionType,
91	                    response.getStatusCode().value(), body);
92	        } catch (JsonProcessingException e) {
93	            // Non-fatal — we still return the real response; just can't cache it.
94	            log.warn("IDEMPOTENCY_STORE_FAIL key={} actionType={}: {}", idempotencyKey, actionType, e.getMessage());
95	        }
96	
97	        return response;
98	    }
99	}
